class Solution:
    def searchMatrix(self, matrix: List[List[int]], target: int) -> bool:
        size = len(matrix[0]) -1
        row = bisect.bisect_left(matrix, target, key=operator.itemgetter(size))
        if row >= len(matrix):
            return False
        column = bisect.bisect_left(matrix[row], target)

        return matrix[row][column] == target
